/**
 * This program calculates the total number of seconds
 * in a week, considering that one day has 86400 seconds
 * and a week consists of 7 days.
 */
package com.handsOn1;
public class M1SecondsCalculator {
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int days=7;
		int sec=86400;
		int total=days*sec;
		System.out.println("Total sec: "+total);
	}
}
